 To create a C++ program that reads a text file line by line and counts the occurrences of a specific word, follow the steps below. In this example, we'll use the word "apple" as the target keyword.

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <map>

std::ifstream file("input.txt"); // Replace "input.txt" with your file path
std::string searchWord = "apple";
std::map<size_t, int> wordCount; // Use a map to store the index and count of each occurrence
std::string line;
size_t startPos = 0;

int main() {
    if (!file.is_open()) {
        std::cerr << "Error opening file." << std::endl;
        return 1;
    }

    int occurrences = 0;
    while (std::getline(file, line)) {
        startPos = 0; // Reset the position marker for each new line
        size_t pos = line.find(searchWord, startPos); // Search for the word in the current line

        while (pos != std::string::npos) { // If the word is found, increment the counter and store the index (for debugging purposes)
            occurrences++;
            if (wordCount.find(pos) != wordCount.end()) { // If the index is already in the map, it means there's a consecutive occurrence – you can choose to treat this as a single instance or multiple depending on your requirements. In this example, we'll count each instance separately.
                // (Do nothing, as we have a duplicate entry)
            } else {
                wordCount[pos] = 1;
            }
            startPos = pos + searchWord.length(); // Move the position marker to the end of the word for the next search
            pos = line.find(searchWord, startPos); // Continue searching for additional occurrences in the same line
        }
    }

    if (file.is_open()) { // Close the file after processing
        file.close();
    }

    std::cout << "The word \"" << searchWord << "\" occurs " << occurrences << " times in the file." << std::endl;

    return 0;
}
```

This program reads a text file named `input.txt` and searches for the word "apple" within each line. It keeps track of the number of occurrences and stores the index of each occurrence in a map (for debugging purposes). Make sure to replace `"input.txt"` with the actual path to your input file.
